package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class CSVFormatTest {

    private Reader mockReader;

    @BeforeEach
    public void setUp() {
        mockReader = mock(Reader.class);
    }

    @Test
    public void testParse_ReturnsCSVParserInstance() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        CSVParser mockParser = mock(CSVParser.class);

        try (MockedStatic<CSVParser> mockedStatic = Mockito.mockStatic(CSVParser.class)) {
            mockedStatic.when(() -> new CSVParser(mockReader, format)).thenReturn(mockParser);

            CSVParser parser = format.parse(mockReader);

            assertNotNull(parser);
            assertSame(mockParser, parser);
        }
    }

    @Test
    public void testParse_NullReader_ThrowsNullPointerException() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertThrows(NullPointerException.class, () -> format.parse(null));
    }

}
